35	@MainActor
36	@Observable
37	final class ModelManager {
38	    private let modelsDirectory: URL
39	    private let defaultsKey = "ThinkAloud.modelProfile"
40	
41	    private(set) var profile: ModelProfile {
42	        didSet {
43	            UserDefaults.standard.set(profile.rawValue, forKey: defaultsKey)
44	            if profile != oldValue {
45	                rebuildRuntime()
46	            }
47	        }
48	    }
49	
50	    private let chinesePreferenceKey = "ThinkAloud.chinesePreference"
51	    var chinesePreference: ChinesePreference {
52	        didSet {
53	            UserDefaults.standard.set(chinesePreference.rawValue, forKey: chinesePreferenceKey)
54	        }
55	    }
56	
57	    private let idleTimeoutKey = "ThinkAloud.idleTimeout"
58	    var idleTimeout: IdleTimeout {
59	        didSet {
60	            UserDefaults.standard.set(idleTimeout.rawValue, forKey: idleTimeoutKey)
61	            scheduleIdleEvictionIfNeeded()
62	        }
63	    }
64	
65	    private(set) var runtimeStatus: ASRRuntimeStatus = .unloaded
66	    private(set) var lastError: String?
67	    private(set) var lastActivityAt: Date = .distantPast
68	
69	    private var runtimeRef: any ASRRuntime
70	    private var statusPollingTask: Task<Void, Never>?
71	    private var idleEvictionTask: Task<Void, Never>?
72	
73	    init(modelsDirectory: URL) {
74	        self.modelsDirectory = modelsDirectory
75	        let stored = UserDefaults.standard.string(forKey: defaultsKey).flatMap(ModelProfile.init(rawValue:)) ?? .accurate
76	        self.profile = stored
77	        let storedPref = UserDefaults.standard.string(forKey: chinesePreferenceKey).flatMap(ChinesePreference.init(rawValue:)) ?? .model
78	        self.chinesePreference = storedPref
79	        let storedTimeout = UserDefaults.standard.string(forKey: idleTimeoutKey).flatMap(IdleTimeout.init(rawValue:)) ?? .tenMinutes
80	        self.idleTimeout = storedTimeout
81	        self.runtimeRef = ASRRuntimeFactory.make(profile: stored, cacheDirectory: modelsDirectory)
82	    }
83	
84	    var modelID: String { profile.modelID }
85	
86	    var runtime: any ASRRuntime { runtimeRef }
87	
88	    func setProfile(_ new: ModelProfile) {
89	        profile = new
90	    }
91	
92	    /// Mark the model as actively in use. Resets the idle-eviction countdown.
93	    func recordActivity() {
94	        lastActivityAt = Date()
95	        scheduleIdleEvictionIfNeeded()
96	    }
97	
98	    func preloadNow() {
99	        let runtime = runtimeRef
100	        startStatusPolling()
101	        Task { @MainActor in
102	            do {
103	                try await runtime.preload()
104	                self.recordActivity()
105	                self.pruneRedundantHFCache()
106	            } catch {
107	                self.lastError = String(describing: error)
108	            }
109	            await self.stopStatusPollingAndSync()
110	        }
111	    }
112	
113	    func refreshStatus() {
114	        let runtime = runtimeRef
115	        Task { @MainActor in
116	            self.runtimeStatus = await runtime.status()
117	        }
118	    }
119	
120	    /// Manual unload — clears in-memory weights immediately. Cached files on disk are kept.
121	    func unloadNow() {
122	        idleEvictionTask?.cancel()
123	        idleEvictionTask = nil
124	        let runtime = runtimeRef
125	        Task { @MainActor in
126	            await runtime.unload()
127	            self.runtimeStatus = await runtime.status()
128	            NSLog("ThinkAloud: model unloaded manually")
129	        }
130	    }
131	
132	    private func startStatusPolling() {
133	        statusPollingTask?.cancel()
134	        let runtime = runtimeRef
135	        statusPollingTask = Task { @MainActor [weak self] in
136	            while !Task.isCancelled {
137	                let s = await runtime.status()
138	                self?.runtimeStatus = s
139	                if case .ready = s { return }
140	                if case .failed = s { return }
141	                try? await Task.sleep(nanoseconds: 250_000_000)
142	            }
143	        }
144	    }
145	
146	    private func stopStatusPollingAndSync() async {
147	        statusPollingTask?.cancel()
148	        statusPollingTask = nil
149	        runtimeStatus = await runtimeRef.status()
150	    }
151	
152	    private func rebuildRuntime() {
153	        idleEvictionTask?.cancel()
154	        idleEvictionTask = nil
155	        runtimeRef = ASRRuntimeFactory.make(profile: profile, cacheDirectory: modelsDirectory)
156	        runtimeStatus = .unloaded
157	        lastError = nil
158	        lastActivityAt = .distantPast
159	    }
160	
161	    private func scheduleIdleEvictionIfNeeded() {
162	        idleEvictionTask?.cancel()
163	        guard let timeout = idleTimeout.seconds else { return }
164	        let runtime = runtimeRef
165	        let activityAt = lastActivityAt
166	        idleEvictionTask = Task { @MainActor [weak self] in
167	            // Sleep until the timeout has elapsed since the recorded activity.
168	            let now = Date()
169	            let elapsed = now.timeIntervalSince(activityAt)
170	            let remaining = max(timeout - elapsed, 0)
171	            try? await Task.sleep(nanoseconds: UInt64(remaining * 1_000_000_000))
172	            if Task.isCancelled { return }
173	            guard let self else { return }
174	            // Confirm still idle: lastActivityAt must not have moved.
175	            if self.lastActivityAt != activityAt { return }
176	            // Only unload if currently ready.
177	            if case .ready = await runtime.status() {
178	                await runtime.unload()
179	                self.runtimeStatus = await runtime.status()
180	                NSLog("ThinkAloud: model auto-unloaded after idle timeout=\(timeout)s")
181	            }
182	        }
183	    }
184	
185	    var modelCacheURL: URL { modelsDirectory }
186	
187	    // MARK: - Per-profile management (Advanced pane)
188	
189	    /// Resolves the on-disk snapshot directory for any profile (matches mlx-audio's layout).
190	    func snapshotURL(for profile: ModelProfile) -> URL {
191	        let cache = HubCache(cacheDirectory: modelsDirectory)
192	        return ASRRuntimeFactory.snapshotDirectory(for: profile.modelID, cache: cache)
193	    }
194	
195	    func cacheSize(for profile: ModelProfile) -> Int64 {
196	        directorySize(snapshotURL(for: profile))
197	    }
198	
199	    func isDownloaded(_ profile: ModelProfile) -> Bool {
200	        ASRRuntimeFactory.hasModelFiles(in: snapshotURL(for: profile))
201	    }
202	
203	    /// Downloads a profile's weights to disk. For the active profile this just calls preload();
204	    /// for non-active profiles it spins up a transient runtime, fetches, then unloads its weights.
205	    func downloadProfile(_ profile: ModelProfile) async throws {
206	        if profile == self.profile {
207	            try await runtimeRef.preload()
208	            return
209	        }
210	        let transient = ASRRuntimeFactory.make(profile: profile, cacheDirectory: modelsDirectory)
211	        try await transient.preload()
212	        await transient.unload()
213	        pruneRedundantHFCache()
214	    }
215	
216	    /// Removes a profile's snapshot directory and its parallel HF blob cache. If it's the
217	    /// currently-selected profile, the active runtime is unloaded first to release file handles.
218	    func removeProfile(_ profile: ModelProfile) throws {
219	        if profile == self.profile {
220	            unloadNow()
221	        }
222	        let snapshot = snapshotURL(for: profile)
223	        if FileManager.default.fileExists(atPath: snapshot.path) {
224	            try FileManager.default.removeItem(at: snapshot)
225	        }
226	        // Also clear the HF-style cache if it's still around (parallel layout from huggingface-swift).
227	        let parts = profile.modelID.split(separator: "/")
228	        if parts.count == 2 {
229	            let hfFolder = "models--\(parts[0])--\(parts[1])"
230	            let hfDir = modelsDirectory.appendingPathComponent(hfFolder)
231	            if FileManager.default.fileExists(atPath: hfDir.path) {
232	                try? FileManager.default.removeItem(at: hfDir)
233	            }
234	        }
235	    }
236	
237	    /// mlx-audio-swift loads from `<models>/mlx-audio/<id>/` (flat copies). The downloader
238	    /// also leaves a parallel HF-style cache at `<models>/models--org--repo/` (snapshots +
239	    /// blobs). Once mlx-audio has the flat copy it never reads the HF cache again, so the
240	    /// HF directory is redundant and can be safely removed to reclaim ~half the disk usage.
241	    @discardableResult
242	    func pruneRedundantHFCache() -> Int64 {
243	        let fm = FileManager.default
