5	@MainActor
6	final class TextInsertionManager {
7	    enum InsertionError: Error, LocalizedError {
8	        case accessibilityDenied
9	        case clipboardWriteFailed
10	        case eventPostFailed
11	
12	        var errorDescription: String? {
13	            switch self {
14	            case .accessibilityDenied: return "Accessibility permission is required to paste text into other apps."
15	            case .clipboardWriteFailed: return "Failed to write to the clipboard."
16	            case .eventPostFailed: return "Failed to post the paste keyboard event."
17	            }
18	        }
19	    }
20	
21	    /// Result describing what happened during insertion.
22	    struct InsertionOutcome: Sendable {
23	        let inserted: Bool
24	        let copiedToClipboard: Bool
25	        let message: String
26	    }
27	
28	    static let restoreDelay: TimeInterval = 0.3
29	
30	    /// Inserts the given text into the previously focused app via paste, falling back to clipboard-only if Accessibility is unavailable.
31	    func insert(_ text: String, into focus: FocusContext?) async -> InsertionOutcome {
32	        let pasteboard = NSPasteboard.general
33	        let previousItems = capturePasteboardItems(pasteboard)
34	
35	        pasteboard.clearContents()
36	        let writeSuccess = pasteboard.setString(text, forType: .string)
37	        guard writeSuccess else {
38	            return InsertionOutcome(inserted: false, copiedToClipboard: false, message: String(localized: "Failed to write to clipboard."))
39	        }
40	
41	        guard ensureAccessibility(prompt: true) else {
42	            return InsertionOutcome(inserted: false, copiedToClipboard: true, message: String(localized: "Accessibility permission missing. Text copied to clipboard — please paste manually."))
43	        }
44	
45	        if let pid = focus?.processID, let app = NSRunningApplication(processIdentifier: pid) {
46	            app.activate(options: [])
47	            try? await Task.sleep(nanoseconds: 80_000_000)
48	        }
49	
50	        let posted = postPasteEvent()
51	        if !posted {
52	            return InsertionOutcome(inserted: false, copiedToClipboard: true, message: String(localized: "Failed to send paste event. Text copied — please paste manually."))
53	        }
54	
55	        try? await Task.sleep(nanoseconds: UInt64(Self.restoreDelay * 1_000_000_000))
56	        restorePasteboardItems(previousItems, on: pasteboard)
57	        return InsertionOutcome(inserted: true, copiedToClipboard: true, message: String(localized: "Inserted."))
58	    }
59	
60	    /// Returns true if accessibility is granted. When prompt is true, surfaces the system prompt the first time it's checked.
61	    @discardableResult
62	    func ensureAccessibility(prompt: Bool) -> Bool {
63	        let key = "AXTrustedCheckOptionPrompt"
64	        let options: CFDictionary = [key: prompt] as CFDictionary
65	        return AXIsProcessTrustedWithOptions(options)
66	    }
67	
68	    private func postPasteEvent() -> Bool {
69	        guard let source = CGEventSource(stateID: .combinedSessionState) else { return false }
70	        let vKeyCode: CGKeyCode = 0x09 // "v"
