256	    private func download(_ profile: ModelProfile) {
257	        let free = freeSpaceAtModelsVolume()
258	        if free < lowDiskThresholdBytes {
259	            availableBytes = free
260	            lowDiskPrompt = profile
261	            return
262	        }
263	        performDownload(profile)
264	    }
265	
266	    private func performDownload(_ profile: ModelProfile) {
267	        inflightDownloads.insert(profile)
268	        error = nil
269	        Task { @MainActor in
270	            do {
271	                try await container.modelManager.downloadProfile(profile)
272	            } catch {
