280	    /// Free bytes on the volume that hosts the models cache. Uses
281	    /// `volumeAvailableCapacityForImportantUsageKey` so it accounts for purgeable storage the
282	    /// system will reclaim under pressure (closer to what Finder shows).
283	    private func freeSpaceAtModelsVolume() -> Int64 {
284	        let url = container.modelManager.modelCacheURL
285	        let values = try? url.resourceValues(forKeys: [.volumeAvailableCapacityForImportantUsageKey])
