300	        }
301	    }
302	
303	    private func formatBytes(_ bytes: Int64) -> String {
304	        let f = ByteCountFormatter()
305	        f.allowedUnits = [.useMB, .useGB]
306	        f.countStyle = .file
307	        return f.string(fromByteCount: bytes)
308	    }
