import AppKit
import SwiftUI

struct AdvancedPane: View {
    @Environment(AppContainer.self) private var container

    @State private var inflightDownloads: Set<ModelProfile> = []
    @State private var inflightRemovals: Set<ModelProfile> = []
    @State private var error: String?
    @State private var refreshToken = 0  // bumped to force re-read of cacheSize after mutations

    @State private var lowDiskPrompt: ModelProfile?
    @State private var availableBytes: Int64 = 0

    @State private var hfTokenDraft: String = ""
    @State private var hfStatus: HFStatus = .idle

    /// Trigger the low-disk confirmation when free space on the models volume drops below this.
    private let lowDiskThresholdBytes: Int64 = 5 * 1_000_000_000

    enum HFStatus: Equatable {
        case idle
        case testing
        case verified(String)
        case failed(String)
    }

    var body: some View {
        Form {
            Section {
                ForEach(ModelProfile.allCases) { profile in
                    modelRow(profile)
                }
            } header: {
                Text("Models")
            } footer: {
                Text("Download additional variants ahead of time, or remove ones you no longer use to reclaim disk space.")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            .id(refreshToken)  // Bumps after a download/remove so cacheSize and isDownloaded re-read from disk.

            huggingFaceSection

            if let error {
                Section {
                    Text(error)
                        .font(.caption)
                        .foregroundStyle(.red)
                }
            }
        }
        .formStyle(.grouped)
        .padding(.horizontal)
        .alert(
            String(localized: "Disk space low"),
            isPresented: Binding(
                get: { lowDiskPrompt != nil },
                set: { if !$0 { lowDiskPrompt = nil } }
            ),
            presenting: lowDiskPrompt
        ) { profile in
            Button(String(localized: "Download anyway"), role: .destructive) {
                performDownload(profile)
            }
            Button(String(localized: "Cancel"), role: .cancel) {}
        } message: { _ in
            Text("Only \(formatBytes(availableBytes)) free on the models volume. Continue downloading?")
        }
        .onAppear {
            // Don't pre-fill the actual token — show empty field so a fresh save replaces it.
            hfTokenDraft = ""
            if let v = container.hfTokenStore.verifiedUsername {
                hfStatus = .verified(v)
            }
        }
    }

    // MARK: - HF section

    private var huggingFaceSection: some View {
        Section {
            HStack {
                Text("Token")
                Spacer()
                if container.hfTokenStore.hasToken {
                    StatusBadge(tone: .ok, text: String(localized: "Saved"))
                } else {
                    StatusBadge(tone: .neutral, text: String(localized: "Not set"))
                }
            }
            SecureField(String(localized: "hf_… (paste here, then Save)"), text: $hfTokenDraft)
                .textFieldStyle(.roundedBorder)
            HStack {
                Button(String(localized: "Save token")) {
                    saveToken()
                }
                .disabled(hfTokenDraft.isEmpty)
                Button(String(localized: "Test connection")) {
                    testConnection()
                }
                .disabled(!container.hfTokenStore.hasToken)
                Spacer()
                if container.hfTokenStore.hasToken {
                    Button(role: .destructive) {
                        clearToken()
                    } label: {
                        Text(String(localized: "Clear"))
                    }
                    .controlSize(.small)
                }
            }
            switch hfStatus {
            case .idle:
                EmptyView()
            case .testing:
                HStack(spacing: 6) {
                    ProgressView().controlSize(.mini)
                    Text("Testing…")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
            case .verified(let user):
                Text("Signed in as **\(user)**")
                    .font(.caption)
                    .foregroundStyle(.green)
            case .failed(let msg):
                Text(msg)
                    .font(.caption)
                    .foregroundStyle(.red)
                    .lineLimit(2)
            }
        } header: {
            Text("Hugging Face")
        } footer: {
            Text("Used to push the dataset from the browser window. Token is stored in macOS Keychain.")
                .font(.caption)
                .foregroundStyle(.secondary)
        }
    }

    private func saveToken() {
        do {
            try container.hfTokenStore.save(token: hfTokenDraft)
            hfTokenDraft = ""
            hfStatus = .idle
        } catch {
            hfStatus = .failed(String(localized: "Keychain save failed: \(error.localizedDescription)"))
        }
    }

    private func clearToken() {
        do {
            try container.hfTokenStore.clear()
            hfTokenDraft = ""
            hfStatus = .idle
        } catch {
            hfStatus = .failed(String(localized: "Keychain clear failed: \(error.localizedDescription)"))
        }
    }

    private func testConnection() {
        guard let token = container.hfTokenStore.token else { return }
        hfStatus = .testing
        Task { @MainActor in
            let client = HFHubClient(token: token)
            do {
                let me = try await client.whoami()
                container.hfTokenStore.verifiedUsername = me.name
                hfStatus = .verified(me.name)
            } catch {
                hfStatus = .failed(String(localized: "Connection failed: \(error.localizedDescription)"))
            }
        }
    }

    @ViewBuilder
    private func modelRow(_ profile: ModelProfile) -> some View {
        let isCurrent = container.modelManager.profile == profile
        let downloaded = container.modelManager.isDownloaded(profile)
        let size = container.modelManager.cacheSize(for: profile)
        let isDownloading = inflightDownloads.contains(profile)
        let isRemoving = inflightRemovals.contains(profile)

        HStack(alignment: .top, spacing: 12) {
            VStack(alignment: .leading, spacing: 4) {
                HStack(spacing: 6) {
                    Text(profile.shortName).fontWeight(.semibold)
                    if isCurrent {
                        Text("Current")
                            .font(.caption2)
                            .padding(.horizontal, 6)
                            .padding(.vertical, 2)
                            .background(Color.accentColor.opacity(0.18), in: Capsule())
                            .foregroundStyle(Color.accentColor)
                    }
                }
                Text(profile.modelID)
                    .font(.caption)
                    .foregroundStyle(.secondary)
                    .lineLimit(1)
                    .truncationMode(.middle)
                statusLine(downloaded: downloaded, size: size, isDownloading: isDownloading, isRemoving: isRemoving)
            }
            Spacer()
            VStack(alignment: .trailing, spacing: 6) {
                if downloaded {
                    DestructiveButton(
                        "Remove",
                        confirmMessage: "Delete this model from disk? It will need to re-download next time you select it.",
                        confirmLabel: "Remove"
                    ) {
                        remove(profile)
                    }
                    .controlSize(.small)
                    .disabled(isRemoving)
                } else {
                    Button(String(localized: "Download")) {
                        download(profile)
                    }
                    .controlSize(.small)
                    .disabled(isDownloading)
                }
            }
        }
        .padding(.vertical, 4)
    }

    @ViewBuilder
    private func statusLine(downloaded: Bool, size: Int64, isDownloading: Bool, isRemoving: Bool) -> some View {
        if isDownloading {
            HStack(spacing: 6) {
                ProgressView().controlSize(.mini)
                Text("Downloading…")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
        } else if isRemoving {
            HStack(spacing: 6) {
                ProgressView().controlSize(.mini)
                Text("Removing…")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
        } else if downloaded {
            Text("Downloaded · \(formatBytes(size))")
                .font(.caption)
                .foregroundStyle(.secondary)
        } else {
            Text("Not downloaded")
                .font(.caption)
                .foregroundStyle(.secondary)
        }
    }

    private func download(_ profile: ModelProfile) {
        let free = freeSpaceAtModelsVolume()
        if free < lowDiskThresholdBytes {
            availableBytes = free
            lowDiskPrompt = profile
            return
        }
        performDownload(profile)
    }

    private func performDownload(_ profile: ModelProfile) {
        inflightDownloads.insert(profile)
        error = nil
        Task { @MainActor in
            do {
                try await container.modelManager.downloadProfile(profile)
            } catch {
                self.error = String(localized: "Download failed: \(error.localizedDescription)")
            }
            inflightDownloads.remove(profile)
            refreshToken &+= 1
        }
    }

    /// Free bytes on the volume that hosts the models cache. Uses
    /// `volumeAvailableCapacityForImportantUsageKey` so it accounts for purgeable storage the
    /// system will reclaim under pressure (closer to what Finder shows).
    private func freeSpaceAtModelsVolume() -> Int64 {
        let url = container.modelManager.modelCacheURL
        let values = try? url.resourceValues(forKeys: [.volumeAvailableCapacityForImportantUsageKey])
        return Int64(values?.volumeAvailableCapacityForImportantUsage ?? 0)
    }

    private func remove(_ profile: ModelProfile) {
        inflightRemovals.insert(profile)
        error = nil
        Task { @MainActor in
            do {
                try container.modelManager.removeProfile(profile)
            } catch {
                self.error = String(localized: "Remove failed: \(error.localizedDescription)")
            }
            inflightRemovals.remove(profile)
            refreshToken &+= 1
        }
    }

    private func formatBytes(_ bytes: Int64) -> String {
        let f = ByteCountFormatter()
        f.allowedUnits = [.useMB, .useGB]
        f.countStyle = .file
        return f.string(fromByteCount: bytes)
    }
}

import AppKit
import Foundation
import Observation

@MainActor
@Observable
final class PopupCoordinator {
    private let permissions: PermissionsService
    private let modelManager: ModelManager
    private let recorder: AudioRecorder
    private let insertion: TextInsertionManager
    private let datasetStore: DatasetStore
    private let audioFileStore: AudioFileStore

    let viewModel = PopupViewModel()
    private let windowController = PopupWindowController()

    private var elapsedTimerTask: Task<Void, Never>?
    private var levelTask: Task<Void, Never>?
    private var lastResult: ASRResult?
    private var lastRecording: RecordingResult?

    init(
        permissions: PermissionsService,
        modelManager: ModelManager,
        recorder: AudioRecorder,
        insertion: TextInsertionManager,
        datasetStore: DatasetStore,
        audioFileStore: AudioFileStore
    ) {
        self.permissions = permissions
        self.modelManager = modelManager
        self.recorder = recorder
        self.insertion = insertion
        self.datasetStore = datasetStore
        self.audioFileStore = audioFileStore
    }

    func invoke() {
        NSLog("ThinkAloud: invoke() phase=\(viewModel.phase)")
        switch viewModel.phase {
        case .recording, .transcribing, .review:
            // .review must early-return so that ⌥Space on a review popup goes to insertAndSave
            // (the sibling handler) rather than restarting recording and discarding the transcript.
            return
        case .idle, .error:
            break
        }
        modelManager.recordActivity()
        viewModel.reset()

        let focus = FocusContext.capture()
        viewModel.focusContext = focus

        windowController.show(viewModel: viewModel, coordinator: self, modelManager: modelManager)
        NSLog("ThinkAloud: popup shown, focus=\(focus.appName ?? "?")")

        Task { @MainActor in
            await self.startRecording()
        }
        modelManager.preloadNow()
    }

    func stopAndTranscribe() {
        // Only meaningful from .recording. Guard so spurious calls (e.g. duplicated hotkey) don't
        // try to stop a recorder that isn't running.
        guard case .recording = viewModel.phase else { return }
        Task { @MainActor in
            await self.finishRecordingAndTranscribe()
        }
    }

    func cancel() {
        Task { @MainActor in
            await self.recorder.cancel()
            self.elapsedTimerTask?.cancel()
            self.levelTask?.cancel()
            self.elapsedTimerTask = nil
            self.levelTask = nil
            self.lastRecording = nil
            self.lastResult = nil
            self.viewModel.reset()
            self.windowController.close()
        }
    }

    func insertOnly() {
        guard canInsertNow else { return }
        Task { @MainActor in
            await self.performInsert(save: false)
        }
    }

    func insertAndSave() {
        guard canInsertNow else { return }
        Task { @MainActor in
            await self.performInsert(save: true)
        }
    }

    var settingsOpener: (() -> Void)?

    func openSettings() {
        settingsOpener?()
    }

    private var canInsertNow: Bool {
        guard case .review = viewModel.phase else { return false }
        if viewModel.isStreaming { return false }
        if viewModel.editedTranscript.isEmpty { return false }
        return true
    }

    // MARK: - Internals

    private func startRecording() async {
        NSLog("ThinkAloud: startRecording entry, mic=\(permissions.microphoneStatus)")
        guard permissions.microphoneStatus != .denied else {
            viewModel.phase = .error(String(localized: "Microphone permission is required. Open Settings to grant access, then try again."))
            return
        }
        if permissions.microphoneStatus == .notDetermined {
            NSLog("ThinkAloud: requesting microphone permission")
            await permissions.requestMicrophone()
            NSLog("ThinkAloud: mic permission now \(permissions.microphoneStatus)")
        }
        guard permissions.microphoneStatus == .granted else {
            viewModel.phase = .error(String(localized: "Microphone permission is required. Open Settings to grant access, then try again."))
            return
        }

        do {
            try await recorder.start(levelCallback: { [weak self] sample in
                Task { @MainActor in
                    self?.viewModel.levelRMS = sample.rms
                    self?.viewModel.levelPeak = sample.peak
                }
            })
        } catch {
            NSLog("ThinkAloud: recorder start failed: \(error)")
            viewModel.phase = .error(String(describing: error))
            return
        }
        NSLog("ThinkAloud: recording started")
        viewModel.phase = .recording
        startElapsedTimer()
    }

    private func startElapsedTimer() {
        elapsedTimerTask?.cancel()
        let recorder = recorder
        elapsedTimerTask = Task { @MainActor [weak self] in
            var tick = 0
            while !Task.isCancelled {
                let seconds = await recorder.elapsedSeconds
                self?.viewModel.elapsedSeconds = seconds
                // Tick recordActivity once per second so the idle-eviction timer in ModelManager
                // never tries to unload weights while we're actively recording.
                if tick % 10 == 0 {
                    self?.modelManager.recordActivity()
                }
                tick &+= 1
                try? await Task.sleep(nanoseconds: 100_000_000)
            }
        }
    }

    private func finishRecordingAndTranscribe() async {
        elapsedTimerTask?.cancel()
        elapsedTimerTask = nil

        let recordingResult: RecordingResult
        do {
            recordingResult = try await recorder.stop()
        } catch {
            viewModel.phase = .error(String(describing: error))
            return
        }
        lastRecording = recordingResult

        viewModel.phase = .transcribing

        // Streaming transcription: switch to .review as soon as the first token arrives so
        // the user sees tokens appear in the editor live.
        let runtime = modelManager.runtime
        let style = modelManager.chinesePreference
        viewModel.rawTranscript = ""
        viewModel.editedTranscript = ""
        viewModel.isStreaming = true
        var accumulated = ""
        var receivedAny = false
        var finalResult: ASRResult?

        do {
            for try await event in runtime.transcribeStream(samples: recordingResult.samples, sampleRate: recordingResult.sampleRate, options: ASROptions(language: nil)) {
                switch event {
                case .token(let token):
                    accumulated += token
                    if !receivedAny {
                        receivedAny = true
                        viewModel.phase = .review
                    }
                    viewModel.rawTranscript = accumulated
                    viewModel.editedTranscript = TranscriptPostProcessor.apply(style, to: accumulated)
                case .result(let r):
                    finalResult = r
                    viewModel.rawTranscript = r.text
                    viewModel.editedTranscript = TranscriptPostProcessor.apply(style, to: r.text)
                    viewModel.transcribeDurationMs = r.durationMs
                    viewModel.asrModelID = r.modelID
                    viewModel.phase = .review
                }
            }
            viewModel.isStreaming = false
            lastResult = finalResult
            modelManager.recordActivity()
            if !receivedAny && finalResult == nil {
                viewModel.phase = .error(String(localized: "No transcription produced."))
            }
        } catch {
            viewModel.isStreaming = false
            modelManager.recordActivity()
            viewModel.phase = .error(String(describing: error))
        }
    }

    private func performInsert(save: Bool) async {
        // Snapshot everything we need from the view model BEFORE closing the popup, since
        // closing the popup will reset state.
        let editedText = viewModel.editedTranscript
        let rawText = viewModel.rawTranscript
        let focus = viewModel.focusContext
        let recording = lastRecording
        let result = lastResult
        let saveFlag = save

        // Close popup FIRST — otherwise the popup window holds keyboard focus and our
        // simulated Cmd+V lands in the popup's own TextEditor instead of the source app.
        windowController.close()
        viewModel.reset()

        // Give the OS a brief moment to transfer keyboard focus back to the source app
        // after our nonactivating panel goes away.
        try? await Task.sleep(nanoseconds: 120_000_000)

        let outcome = await insertion.insert(editedText, into: focus)
        NSLog("ThinkAloud: insertion outcome inserted=\(outcome.inserted) clipboard=\(outcome.copiedToClipboard) msg=\(outcome.message)")
        InsertionFeedback.notifyIfNeeded(outcome: outcome)

        if saveFlag, let recording, let result {
            do {
                let recordID = DatasetRecord.generateID(date: recording.startedAt)
                let stored = try await audioFileStore.persist(samples: recording.samples, sampleRate: Double(recording.sampleRate), recordID: recordID, at: recording.startedAt)
                let createdAt = ISO8601DateFormatter().string(from: recording.startedAt)
                let record = DatasetRecord(
                    id: recordID,
                    createdAt: createdAt,
                    audioPath: stored.relativePath,
                    durationMs: recording.durationMs,
                    sampleRate: recording.sampleRate,
                    channels: recording.channels,
                    sourceAppBundleID: focus?.appBundleID,
                    sourceAppName: focus?.appName,
                    asrProvider: "mlx-audio-swift",
                    asrModel: result.modelID,
                    asrRuntime: result.runtimeID,
                    asrConfigJSON: nil,
                    rawTranscript: rawText,
                    editedTranscript: editedText,
                    inserted: outcome.inserted,
                    savedToDataset: true,
                    language: result.language,
                    metadataJSON: nil
                )
                try await datasetStore.save(record)
            } catch {
                NSLog("ThinkAloud: dataset save failed: \(error)")
            }
        }

        lastRecording = nil
        lastResult = nil
    }
}

